extension VM {

    /// Execute a bytecode plan
    func executePlan(
        withContext ctx: EvaluationContext,
        planIndex: Int,
        builtins: [BuiltinImpl?] = []
    ) throws -> ResultSet {
        guard planIndex < policy.plans.count else {
            throw Error.invalidPayloadLength
        }

        let plan = policy.plans[planIndex]
        let data = try ctx.store.read(from: StoreKeyPath(["data"]))
        let vmContext = VMContext(
            evaluationContext: ctx,
            policy: policy,
            planMaxLocal: plan.maxLocal,
            data: data,
            builtins: builtins
        )

        for block in plan.blocks {
            let blockResult: BlockResult
            blockResult = try executeBlockSync(context: vmContext, offset: block.offset, size: block.size)
            guard !blockResult.shouldBreak else {
                throw RegoError(code: .internalError, message: "break statement jumped out of frame")
            }
            if blockResult.isUndefined {
                continue
            }
        }

        return vmContext.results
    }

    /// Execute multiple blocks, collecting function return values
    internal func executeBlocks(
        context: VMContext,
        blocks: [(offset: Int, size: Int)]
    ) throws -> BlockResult {
        var functionReturnValue: AST.RegoValue?

        for block in blocks {
            let blockResult = try executeBlock(
                context: context,
                offset: block.offset,
                size: block.size
            )
            guard !blockResult.shouldBreak else {
                throw RegoError(code: .internalError, message: "break statement jumped out of frame")
            }
            if blockResult.isUndefined {
                continue
            }
            if let retVal = blockResult.functionReturnValue {
                guard functionReturnValue == nil else {
                    throw RegoError(code: .internalError, message: "multiple return values from a function")
                }
                functionReturnValue = retVal
            }
        }

        return BlockResult(functionReturnValue: functionReturnValue)
    }

    /// Execute a user-defined function
    internal func executeFunction(
        context: VMContext,
        function: Function,
        args: [AST.RegoValue]
    ) throws -> AST.RegoValue {
        context.callDepth += 1
        guard context.callDepth <= context.maxCallDepth else {
            context.callDepth -= 1
            throw RegoError(code: .internalError, message: "max call depth exceeded")
        }

        // Save current locals and install new frame
        let savedLocals = context.locals
        let localsCount = max(function.maxLocal + 1, 2)
        context.locals = context.allocateLocals(count: localsCount)

        // Assign parameters
        for (i, paramIdx) in function.params.enumerated() where i < args.count {
            context.locals[paramIdx] = args[i]
        }

        // Propagate input and data from the caller's frame so that with-patched values are visible
        // to called functions.
        context.locals[localIdxInput] = savedLocals[localIdxInput] ?? .undefined
        context.locals[localIdxData] = savedLocals[localIdxData] ?? .undefined

        defer {
            context.callDepth -= 1
            let callLocals = context.locals
            context.locals = savedLocals
            context.releaseLocals(callLocals, usedCount: localsCount)
        }

        // Execute function blocks
        let result = try executeBlocks(context: context, blocks: function.blocks)

        // Return explicit ReturnLocal value; undefined if none
        let returnValue = result.functionReturnValue ?? .undefined

        return returnValue
    }

    /// Execute a single block (PC loop over instructions)
    internal func executeBlock(
        context: VMContext,
        offset: Int,
        size: Int
    ) throws -> BlockResult {
        let bytecode = policy.bytecode
        var pc = offset
        let endOffset = offset + size

        while pc < endOffset {
            if pc % 256 == 0 && Task.isCancelled {
                throw RegoError(code: .evaluationCancelled, message: "parent task cancelled")
            }

            // Decode header word: [reserved:2 | opcode:6 | length:24] little-endian.
            let word = bytecode.withUnsafeBytes {
                $0.load(fromByteOffset: pc, as: UInt32.self)
            }
            let opcodeRaw = Int((word >> 24) & 0x3F)
            let length = Int(word & 0xFFFFFF)
            pc += 4
            let payloadStart = pc

            // Unified switch over all opcodes: compact ops use `continue` (zero payload — `pc`
            // already advanced past the 4-byte header).  Non-compact ops assign `result` and
            // fall through to advance `pc` by the payload length.
            var result: BlockResult = .success
            switch opcodeRaw {
            // ── Compact opcodes (rawValues 35–41): operand encoded in `length` field ─────────
            case Int(Opcode.isDefined1.rawValue):
                // Direct locals access (not resolveLocal): a single switch on the raw Optional
                // handles nil and .some(.undefined) in one step, avoiding nil-coalescing.
                // See resolveLocal docs for why this exception exists.
                switch context.locals[Local(UInt32(length))] {
                case nil, .some(.undefined): return .undefined
                default: continue
                }
            case Int(Opcode.isUndefined1.rawValue):
                // Direct locals access — same rationale as isDefined1 above.
                switch context.locals[Local(UInt32(length))] {
                case nil, .some(.undefined): continue
                default: return .undefined
                }
            case Int(Opcode.resetLocal1.rawValue):
                context.locals[Local(UInt32(length))] = nil
                continue
            case Int(Opcode.resultSetAdd1.rawValue):
                // Direct locals access — same rationale as isDefined1 above.
                switch context.locals[Local(UInt32(length))] {
                case nil, .some(.undefined): return .undefined
                case .some(let v):
                    context.results.insert(v)
                    continue
                }
            case Int(Opcode.returnLocal1.rawValue):
                return BlockResult(functionReturnValue: context.resolveLocal(idx: Local(UInt32(length))))
            case Int(Opcode.break1.rawValue):
                return BlockResult(breakCounter: UInt32(length))
            case Int(Opcode.assignVar1.rawValue):
                // Payload is [target:12 | source:12] packed in the header length field.
                // Read through resolveLocal so an unbound source is promoted to .undefined,
                // matching the non-compact assignVar path.
                context.locals[Local(UInt32(length) >> 12)] = context.resolveLocal(idx: Local(UInt32(length) & 0xFFF))
                continue
            // ── Non-compact opcodes (rawValues 0–34): `length` is payload byte count ─────────
            // Assignments
            case Int(Opcode.arrayAppend.rawValue):
                result = try execArrayAppend(context: context, payload: bytecode, start: payloadStart, length: length)
            case Int(Opcode.assignInt.rawValue):
                result = try execAssignInt(context: context, payload: bytecode, start: payloadStart, length: length)
            case Int(Opcode.assignVarOnce.rawValue):
                result = try execAssignVarOnce(context: context, payload: bytecode, start: payloadStart, length: length)
            case Int(Opcode.assignVar.rawValue):
                result = try execAssignVar(context: context, payload: bytecode, start: payloadStart, length: length)
            // Control flow
            case Int(Opcode.block.rawValue):
                result = try execBlockStmt(
                    context: context, payload: bytecode, start: payloadStart, length: length)
            case Int(Opcode.break.rawValue):
                result = try execBreak(context: context, payload: bytecode, start: payloadStart, length: length)
            case Int(Opcode.call.rawValue):
                result = try execCall(context: context, payload: bytecode, start: payloadStart, length: length)
            case Int(Opcode.callDynamic.rawValue):
                result = try execCallDynamic(
                    context: context, payload: bytecode, start: payloadStart, length: length)
            // Operations
            case Int(Opcode.dot.rawValue):
                result = try execDot(context: context, payload: bytecode, start: payloadStart, length: length)
            case Int(Opcode.equal.rawValue):
                result = try execEqual(context: context, payload: bytecode, start: payloadStart, length: length)
            // Type checks
            case Int(Opcode.isArray.rawValue):
                result = try execIsArray(context: context, payload: bytecode, start: payloadStart, length: length)
            case Int(Opcode.isDefined.rawValue):
                result = try execIsDefined(context: context, payload: bytecode, start: payloadStart, length: length)
            case Int(Opcode.isObject.rawValue):
                result = try execIsObject(context: context, payload: bytecode, start: payloadStart, length: length)
            case Int(Opcode.isSet.rawValue):
                result = try execIsSet(context: context, payload: bytecode, start: payloadStart, length: length)
            case Int(Opcode.isUndefined.rawValue):
                result = try execIsUndefined(context: context, payload: bytecode, start: payloadStart, length: length)
            // Built-in operations
            case Int(Opcode.len.rawValue):
                result = try execLen(context: context, payload: bytecode, start: payloadStart, length: length)
            // Value construction
            case Int(Opcode.makeArray.rawValue):
                result = try execMakeArray(context: context, payload: bytecode, start: payloadStart, length: length)
            case Int(Opcode.makeNull.rawValue):
                result = try execMakeNull(context: context, payload: bytecode, start: payloadStart, length: length)
            case Int(Opcode.makeNumberInt.rawValue):
                result = try execMakeNumberInt(context: context, payload: bytecode, start: payloadStart, length: length)
            case Int(Opcode.makeNumberRef.rawValue):
                result = try execMakeNumberRef(context: context, payload: bytecode, start: payloadStart, length: length)
            case Int(Opcode.makeObject.rawValue):
                result = try execMakeObject(context: context, payload: bytecode, start: payloadStart, length: length)
            case Int(Opcode.makeSet.rawValue):
                result = try execMakeSet(context: context, payload: bytecode, start: payloadStart, length: length)
            // Control and comparison
            case Int(Opcode.nop.rawValue):
                break  // result stays .success
            case Int(Opcode.notEqual.rawValue):
                result = try execNotEqual(context: context, payload: bytecode, start: payloadStart, length: length)
            case Int(Opcode.not.rawValue):
                result = try execNot(context: context, payload: bytecode, start: payloadStart, length: length)
            // Object operations
            case Int(Opcode.objectInsertOnce.rawValue):
                result = try execObjectInsertOnce(
                    context: context, payload: bytecode, start: payloadStart, length: length)
            case Int(Opcode.objectInsert.rawValue):
                result = try execObjectInsert(context: context, payload: bytecode, start: payloadStart, length: length)
            case Int(Opcode.objectMerge.rawValue):
                result = try execObjectMerge(context: context, payload: bytecode, start: payloadStart, length: length)
            // Variable management
            case Int(Opcode.resetLocal.rawValue):
                result = try execResetLocal(context: context, payload: bytecode, start: payloadStart, length: length)
            case Int(Opcode.resultSetAdd.rawValue):
                result = try execResultSetAdd(context: context, payload: bytecode, start: payloadStart, length: length)
            case Int(Opcode.returnLocal.rawValue):
                result = try execReturnLocal(context: context, payload: bytecode, start: payloadStart, length: length)
            // Collection operations
            case Int(Opcode.scan.rawValue):
                result = try execScan(context: context, payload: bytecode, start: payloadStart, length: length)
            case Int(Opcode.setAdd.rawValue):
                result = try execSetAdd(context: context, payload: bytecode, start: payloadStart, length: length)
            case Int(Opcode.with.rawValue):
                result = try execWith(context: context, payload: bytecode, start: payloadStart, length: length)
            case Int(Opcode.block1.rawValue):
                // Inline block1 to avoid an extra async activation record for the single sub-block call.
                let innerResult: BlockResult
                innerResult = try executeBlockSync(context: context, offset: payloadStart, size: length)
                if innerResult.shouldBreak {
                    result = innerResult.breakByOne()
                }
            // Inner undefined is intentionally ignored: block1 compiles from a single-sub-block
            // IR form where an undefined body means "this alternative didn't match" and execution
            // falls through to the next instruction, not propagated as undefined to the caller.
            default:
                preconditionFailure("unhandled opcode \(opcodeRaw)")
            }

            // .undefined is encoded as BlockResult(breakCounter: 0), so the breakCounter check
            // below already covers it.  Propagate any non-continuing result immediately.
            if result.breakCounter != nil || result.functionReturnValue != nil { return result }

            pc = payloadStart + length
        }

        return .success
    }

    // MARK: - Control Flow

    /// Block: [numBlocks: UInt32][offset1: UInt32][size1: UInt32]...
    /// Implements blockStmt semantics for 0 or 2+ sub-blocks
    func execBlockStmt(context: VMContext, payload: ContiguousArray<UInt8>, start: Int, length: Int) throws
        -> BlockResult
    {
        let numBlocks = context.decodeUInt32(from: payload, at: start)
        guard numBlocks > 0 else { return .success }
        var offset = start + 4

        for _ in 0..<numBlocks {
            let blockOffset = context.decodeUInt32(from: payload, at: offset)
            let blockSizeRaw = context.decodeUInt32(from: payload, at: offset + 4)
            offset += 8

            let result: BlockResult
            result = try self.executeBlockSync(
                context: context,
                offset: Int(blockOffset),
                size: Int(decodeBlockSize(blockSizeRaw))
            )

            if result.shouldBreak {
                // Propagate break after decrementing
                return result.breakByOne()
            }
            if result.isUndefined {
                // Undefined block: skip to next alternative
                continue
            }
            // Success (or functionReturnValue): continue to next sub-block.
            // functionReturnValue is intentionally not propagated here — it is
            // collected by executeBlocks at the function boundary, matching IR semantics.
        }

        return .success
    }

    /// Call: [result: Local][funcIndex: UInt32][argCount: UInt32][args: Operand...]
    /// funcIndex high bit: 0 = user function, 1 = builtin (lower bits = string table index)
    func execCall(context: VMContext, payload: ContiguousArray<UInt8>, start: Int, length: Int) throws
        -> BlockResult
    {
        let result = context.decodeLocal(from: payload, at: start)
        let encodedFuncIndex = context.decodeUInt32(from: payload, at: start + 4)
        let argCount = context.decodeUInt32(from: payload, at: start + 8)

        // Fast path: user function call with exactly 2 args (OPA rules: input + data).
        // Check the memo cache using the raw encoded operands as the key (no value hashing).
        if !isBuiltinCall(encodedFuncIndex) && argCount == 2 {
            let (op0, op0Size) = EncodedOperand.decodeUnchecked(from: payload, at: start + 12)
            let (op1, _) = EncodedOperand.decodeUnchecked(from: payload, at: start + 12 + op0Size)
            let memoKey = CallKey(
                funcIndex: Int32(encodedFuncIndex),
                op0: (UInt32(op0.type.rawValue) << 30) | op0.value,
                op1: (UInt32(op1.type.rawValue) << 30) | op1.value
            )
            if let cached = context[memoKey] {
                if case .undefined = cached { return failWithUndefinedBytecode(context: context) }
                context.assignLocal(idx: result, value: cached)
                return .success
            }

            let funcIndex = decodeFuncIndex(encodedFuncIndex)  // mask sync bit (bit 30)
            let function = policy.functions[funcIndex]
            let arg0 = context.resolveUnchecked(op0)
            let arg1 = context.resolveUnchecked(op1)
            var memoArgs = context.allocateArgs(count: 2)
            defer { context.releaseArgs(memoArgs) }
            memoArgs.append(arg0)
            memoArgs.append(arg1)

            let returnValue: AST.RegoValue
            returnValue = try executeFunctionSync(context: context, function: function, args: memoArgs)
            context[memoKey] = returnValue
            if case .undefined = returnValue { return failWithUndefinedBytecode(context: context) }
            context.assignLocal(idx: result, value: returnValue)
            return .success
        }

        // General path: builtins and user functions with != 2 args
        var args = context.allocateArgs(count: Int(argCount))
        defer {
            context.releaseArgs(args)
        }

        // Decode arguments into pooled array.
        // Note: we do not reject undefined args here for user functions - the function body
        // handles undefined arguments internally. For builtins we check below.
        var currentOffset = start + 12
        for _ in 0..<Int(argCount) {
            let (op, size) = context.decodeOperand(from: payload, at: currentOffset)
            let value = context.resolveUnchecked(op)
            args.append(value)
            currentOffset += size
        }

        // Check if this is a builtin call (high bit set)
        if isBuiltinCall(encodedFuncIndex) {
            // Builtin call: fail immediately if any argument is undefined
            for argValue in args {
                if case .undefined = argValue { return failWithUndefinedBytecode(context: context) }
            }

            let stringIndex = builtinStringIndex(encodedFuncIndex)

            // Create builtin context
            let builtinContext = BuiltinContext(
                tracer: context.evaluationContext.tracer,
                cache: context.evaluationContext.builtinsCache,
                timestamp: context.evaluationContext.timestamp,
                rand: context.builtinsRand
            )

            // Prefer sync dispatch; fall back to async-only builtins.
            let returnValue: AST.RegoValue
            do {
                returnValue = try context.syncSafeBuiltin(at: stringIndex)!(builtinContext, args)
            } catch {
                if context.evaluationContext.strictBuiltins { throw error }
                return failWithUndefinedBytecode(context: context)
            }

            // Store result
            context.assignLocal(idx: result, value: returnValue)
            return .success
        }

        // User-defined function call with != 2 args (no memoization)
        let funcIndex = decodeFuncIndex(encodedFuncIndex)
        let function = policy.functions[funcIndex]

        let returnValue: AST.RegoValue
        returnValue = try executeFunctionSync(context: context, function: function, args: args)

        if case .undefined = returnValue { return failWithUndefinedBytecode(context: context) }
        context.assignLocal(idx: result, value: returnValue)
        return .success
    }

    /// CallDynamic: [result: Local][pathCount: UInt32][path: Operand...][argCount: UInt32][args: Local...]
    func execCallDynamic(context: VMContext, payload: ContiguousArray<UInt8>, start: Int, length: Int) throws
        -> BlockResult
    {
        let result = context.decodeLocal(from: payload, at: start)
        let pathCount = context.decodeUInt32(from: payload, at: start + 4)

        var offset = start + 8

        // Decode path operands
        var funcName = ""
        for i in 0..<Int(pathCount) {
            let (segmentOp, size) = context.decodeOperand(from: payload, at: offset)
            let segment = context.resolveUnchecked(segmentOp)
            offset += size

            guard case .string(let stringValue) = segment else {
                return failWithUndefinedBytecode(context: context)
            }

            if i > 0 {
                funcName += "."
            }
            funcName += stringValue
        }

        // Decode argument count
        let argCount = context.decodeUInt32(from: payload, at: offset)
        offset += 4

        // Allocate args array from pool
        var args = context.allocateArgs(count: Int(argCount))
        defer {
            context.releaseArgs(args)
        }

        // Decode arguments (these are Locals, not Operands)
        // Note: do not reject undefined args — the called function handles them internally,
        // mirroring execCall's behavior for user functions.
        for _ in 0..<Int(argCount) {
            let argLocal = context.decodeLocal(from: payload, at: offset)
            offset += 4
            let argValue = context.resolveLocal(idx: argLocal)
            args.append(argValue)
        }

        // Find function by path.
        guard let function = policy.functions.first(where: { $0.path == funcName }) else {
            return failWithUndefinedBytecode(context: context)
        }

        let returnValue = try executeFunction(context: context, function: function, args: args)

        if case .undefined = returnValue { return failWithUndefinedBytecode(context: context) }
        context.assignLocal(idx: result, value: returnValue)

        return .success
    }

    /// Not: [block content inline]
    func execNot(context: VMContext, payload: ContiguousArray<UInt8>, start: Int, length: Int) throws
        -> BlockResult
    {
        // Execute the nested block — block starts at payload start and fills the entire payload
        let result: BlockResult
        result = try self.executeBlockSync(context: context, offset: start, size: length)

        // Handle break statements
        if let breakCounter = result.breakCounter {
            if breakCounter > 0 {
                // Propagate break after decrementing
                return result.breakByOne()
            }
            // breakCounter == 0 means undefined, so Not succeeds
            return .success
        }

        // If block succeeded (not undefined), Not fails
        return failWithUndefinedBytecode(context: context)
    }

    // MARK: - Collection Operations

    /// Scan: [source: Local][key: Local][value: Local][block content inline]
    func execScan(context: VMContext, payload: ContiguousArray<UInt8>, start: Int, length: Int) throws
        -> BlockResult
    {
        let source = context.decodeLocal(from: payload, at: start)
        let key = context.decodeLocal(from: payload, at: start + 4)
        let value = context.decodeLocal(from: payload, at: start + 8)
        // Block starts immediately after 3 locals (12 bytes)
        let blockOffset = start + 12
        let blockSize = length - 12

        let sourceValue = context.resolveLocal(idx: source)

        // Ensure source is defined and is a collection
        if case .undefined = sourceValue { return failWithUndefinedBytecode(context: context) }
        guard sourceValue.isCollection else { return failWithUndefinedBytecode(context: context) }

        // Iterate over the collection, propagating break and return from the scan body.
        // OPA semantics: break exits the scan loop (consuming one nesting level),
        // return propagates immediately, undefined or success means this iteration
        // didn't match / completed — continue to the next element.
        switch sourceValue {
        case .array(let arr):
            var i = 0
            for element in arr {
                context.assignLocal(idx: key, value: .number(RegoNumber(int: Int64(i))))
                context.assignLocal(idx: value, value: element)
                let blockResult: BlockResult
                blockResult = try self.executeBlockSync(context: context, offset: blockOffset, size: blockSize)
                if blockResult.shouldBreak { return blockResult.breakByOne() }
                if blockResult.functionReturnValue != nil { return blockResult }
                i &+= 1
            }
        case .object(let obj):
            for (k, v) in obj {
                context.assignLocal(idx: key, value: k)
                context.assignLocal(idx: value, value: v)
                let blockResult: BlockResult
                blockResult = try self.executeBlockSync(context: context, offset: blockOffset, size: blockSize)
                if blockResult.shouldBreak { return blockResult.breakByOne() }
                if blockResult.functionReturnValue != nil { return blockResult }
            }
        case .set(let set):
            for val in set {
                context.assignLocal(idx: key, value: val)
                context.assignLocal(idx: value, value: val)
                let blockResult: BlockResult
                blockResult = try self.executeBlockSync(context: context, offset: blockOffset, size: blockSize)
                if blockResult.shouldBreak { return blockResult.breakByOne() }
                if blockResult.functionReturnValue != nil { return blockResult }
            }
        default:
            return failWithUndefinedBytecode(context: context)
        }

        return .success
    }

    /// With: [local: Local][value: Operand][pathCount: UInt32][pathIndices: UInt32...][block content inline]
    func execWith(context: VMContext, payload: ContiguousArray<UInt8>, start: Int, length: Int) throws
        -> BlockResult
    {
        let local = context.decodeLocal(from: payload, at: start)
        let (valueOp, valueSize) = context.decodeOperand(from: payload, at: start + 4)
        let overlayValue = context.resolveUnchecked(valueOp)

        var offset = start + 4 + valueSize

        // Decode path (string-table indices)
        let pathCount = context.decodeUInt32(from: payload, at: offset)
        offset += 4

        var path: [String] = []
        path.reserveCapacity(Int(pathCount))
        for _ in 0..<Int(pathCount) {
            let stringIndex = Int(context.decodeUInt32(from: payload, at: offset))
            offset += 4
            path.append(policy.strings[stringIndex])
        }

        // Block starts at `offset` — fills the remainder of the payload
        let blockOffset = offset
        let blockSize = length - (offset - start)

        // Save current value, apply patch at path
        let toPatch = context.resolveLocal(idx: local)
        let patched = toPatch.patch(with: overlayValue, at: path)
        context.assignLocal(idx: local, value: patched)

        // Push a fresh memo cache for the with-block.
        // `with` patches input/data locals, so any memoized call results from the enclosing
        // scope are stale inside the block — a called rule may return a different value when
        // it sees the patched data.  The cache is popped in the defer, restoring the outer scope.
        context.pushMemoCache()
        defer {
            context.popMemoCache()
            context.assignLocal(idx: local, value: toPatch)
        }

        let result: BlockResult
        result = try self.executeBlockSync(context: context, offset: blockOffset, size: blockSize)

        // Respect the break index from a sub block
        if result.shouldBreak {
            return result.breakByOne()
        }

        // Propagate undefined
        if result.isUndefined {
            return failWithUndefinedBytecode(context: context)
        }

        return result
    }
}

extension OPA.Engine.PreparedQuery {

    /// Returns the result of evaluating the prepared query against the given input.
    ///
    /// - Parameters:
    ///   - input: The input data to evaluate the query against.
    ///   - tracer: (optional) The tracer to use for this evaluation.
    ///   - strictBuiltins: (optional) Whether to run in strict builtin evaluation mode.
    ///                     In strict mode, builtin errors abort evaluation, rather than returning undefined.
    public func evaluate(
        input: AST.RegoValue = .undefined,
        tracer: OPA.Trace.QueryTracer? = nil,
        strictBuiltins: Bool = false
    ) throws -> ResultSet {
        let ctx = EvaluationContext(
            query: self.query,
            input: input,
            store: self.store,
            builtins: self.builtinRegistry,
            tracer: tracer,
            strictBuiltins: strictBuiltins
        )
        return try self.evaluator.evaluate(withContext: ctx, builtins: self.builtins)
    }
}

extension IREvaluator {

    // swift-format-ignore: UseEarlyExits
    func evaluate(withContext ctx: EvaluationContext, builtins: [[BuiltinImpl?]]) throws -> ResultSet {
        let entrypoint = try queryToEntryPoint(ctx.query)
        guard let hit = planIndex[entrypoint] else {
            throw RegoError(code: .unknownQuery, message: "query not found in plan: \(ctx.query)")
        }
        let vm = VM(policy: policies[hit.policyIdx])
        let plan = policies[hit.policyIdx].plans[hit.planIdx]
        guard plan.syncSafe else {
            throw RegoError(
                code: .requiresAsyncEvaluation,
                message: "plan '\(plan.name)' requires async evaluation"
            )
        }
        return try vm.executePlan(
            withContext: ctx, planIndex: hit.planIdx, builtins: builtins[hit.policyIdx])
    }
}
